async def execute(self, inputs):
    a = inputs.get('a') if inputs.get('a') is not None else self.get_parameter('a', 1)
    b = inputs.get('b') if inputs.get('b') is not None else self.get_parameter('b', 1)
    try:
        res = (float(a) if a is not None else 0.0) * (float(b) if b is not None else 0.0)
    except Exception as e:
        try: self.log_info(f'Multiply error: {e}')
        except Exception: pass
        res = None

    await self.set_output('result', res)
    await self.set_output('exec_out', True)
    return {'result': res}
